"""题目服务"""
import json
from sqlalchemy.orm import Session
from ..models.question import Question
from ..schemas.question import QuestionOut, QuestionDetail, QuestionGenerateRequest, QuestionGenerateResponse
from ..knowledge.retriever import retrieve_for_question


def get_questions(
    db: Session,
    module: str = None,
    type: str = None,
    difficulty: int = None,
    skip: int = 0,
    limit: int = 20,
) -> list[QuestionOut]:
    """查询题目列表，支持筛选"""
    query = db.query(Question)
    if module:
        query = query.filter(Question.module == module)
    if type:
        query = query.filter(Question.type == type)
    if difficulty:
        query = query.filter(Question.difficulty == difficulty)
    query = query.order_by(Question.created_at.desc()).offset(skip).limit(limit)
    return [QuestionOut.model_validate(q) for q in query.all()]


def get_question_detail(db: Session, question_id: int) -> QuestionDetail:
    """获取题目详情，包含关联知识卡片"""
    question = db.query(Question).filter(Question.id == question_id).first()
    if not question:
        raise ValueError(f"题目 {question_id} 不存在")

    # 获取关联知识
    tags = []
    if question.knowledge_tags:
        try:
            tags = json.loads(question.knowledge_tags)
        except json.JSONDecodeError:
            pass

    knowledge_cards = retrieve_for_question(tags, n_results=4)

    detail = QuestionDetail.model_validate(question)
    detail.knowledge_cards = knowledge_cards
    return detail


